18	error_t sign_batch(job_2p_t& job, key_t& key, const std::vector<mem_t>& msgs, std::vector<buf_t>& sigs,
19	                   variant_e variant) {
20	  int n_sigs = msgs.size();
21	  if (n_sigs <= 0) return coinbase::error(E_BADARG, "schnorr_2p: empty batch");
22	  sigs.resize(n_sigs);
23	
24	  error_t rv = UNINITIALIZED_ERROR;
25	  ecurve_t curve = key.curve;
26	
27	  const auto& G = curve.generator();
28	  const mod_t& q = curve.order();
29	
30	  std::vector<bn_t> k1(n_sigs), k2(n_sigs);
31	  std::vector<ecc_point_t> R1(n_sigs), R2(n_sigs);
32	  buf_t sid1, sid2, sid;
33	  coinbase::crypto::commitment_t com;
34	  zk::uc_batch_dl_t zk_dl1, zk_dl2;
35	
36	  if (job.is_p1()) {
37	    sid1 = crypto::gen_random_bitlen(SEC_P_COM);
38	    for (int i = 0; i < n_sigs; i++) k1[i] = bn_t::rand(q);
39	    for (int i = 0; i < n_sigs; i++) R1[i] = k1[i] * G;
40	    com.id(sid1, job.get_pid(party_t::p1)).gen(R1);
41	  }
42	  if (rv = job.p1_to_p2(sid1, com.msg)) return rv;
43	
44	  if (job.is_p2()) {
45	    sid2 = crypto::gen_random_bitlen(SEC_P_COM);
46	    for (int i = 0; i < n_sigs; i++) k2[i] = bn_t::rand(q);
47	    for (int i = 0; i < n_sigs; i++) R2[i] = k2[i] * G;
48	    sid = crypto::sha256_t::hash(sid1, sid2);
49	    zk_dl2.prove(R2, k2, sid, 2);
50	  }
51	  if (rv = job.p2_to_p1(R2, zk_dl2, sid2)) return rv;
52	  if (job.is_p1() && R2.size() != size_t(n_sigs))
53	    return coinbase::error(E_CRYPTO, "schnorr_2p: inconsistent batch size (R2)");
54	
55	  if (job.is_p1()) {
56	    // point checks are covered by the zk proof
57	    sid = crypto::sha256_t::hash(sid1, sid2);
58	    if (rv = zk_dl2.verify(R2, sid, 2)) return rv;
59	    zk_dl1.prove(R1, k1, sid, 1);
60	  }
61	  if (rv = job.p1_to_p2(zk_dl1, R1, com.rand)) return rv;
62	
63	  if (job.is_p2()) {
64	    if (R1.size() != size_t(n_sigs)) return coinbase::error(E_CRYPTO, "schnorr_2p: inconsistent batch size (R1)");
65	    // point checks are covered by the zk proof
66	    if (rv = com.id(sid1, job.get_pid(party_t::p1)).open(R1)) return rv;
67	    if (rv = zk_dl1.verify(R1, sid, 1)) return rv;
68	  }
69	
70	  std::vector<ecc_point_t> R(n_sigs);
71	  for (int i = 0; i < n_sigs; i++) R[i] = R1[i] + R2[i];
72	
73	  std::vector<bn_t> e(n_sigs);
74	  if (variant == variant_e::BIP340) {
75	    if (curve != crypto::curve_secp256k1) return coinbase::error(E_BADARG, "BIP340 variant requires secp256k1 curve");
76	    for (int i = 0; i < n_sigs; i++) {
77	      if (msgs[i].size != 32) return coinbase::error(E_BADARG, "schnorr_2p: BIP340 msg size != 32");
78	      if (!msgs[i].data) return coinbase::error(E_BADARG, "schnorr_2p: BIP340 msg is null");
79	      bn_t rx, ry;
80	      R[i].get_coordinates(rx, ry);
81	      if (ry.is_odd()) {
82	        k1[i] = q - k1[i];
83	        k2[i] = q - k2[i];
84	      }
85	      e[i] = crypto::bip340::hash_message(rx, key.Q, msgs[i]);
86	      if (key.Q.get_y().is_odd()) e[i] = q - e[i];
87	    }
88	  } else if (variant == variant_e::EdDSA) {
89	    if (curve != crypto::curve_ed25519) return coinbase::error(E_BADARG, "EdDSA variant requires ed25519 curve");
90	    std::vector<buf_t> e_buf(n_sigs);
91	    for (int i = 0; i < n_sigs; i++) {
92	      e_buf[i] = crypto::sha512_t::hash(R[i], key.Q.to_compressed_bin(), msgs[i]);
93	      e[i] = bn_t::from_bin(e_buf[i].rev()) % q;
94	    }
95	  } else {
96	    cb_assert(false && "schnorr_2p: non-existing variant");
97	  }
98	
99	  std::vector<bn_t> s2(n_sigs);
100	  if (job.is_p2()) {
101	    for (int i = 0; i < n_sigs; i++) {
102	      MODULO(q) s2[i] = e[i] * key.x_share + k2[i];
103	    }
104	  }
105	
106	  if (rv = job.p2_to_p1(s2)) return rv;
107	
108	  if (job.is_p1()) {
109	    if (s2.size() != size_t(n_sigs)) return coinbase::error(E_CRYPTO, "schnorr_2p: inconsistent batch size (s2)");
110	    for (int i = 0; i < n_sigs; i++) {
111	      bn_t s, s1;
112	      MODULO(q) {
113	        s1 = e[i] * key.x_share + k1[i];
114	        s = s1 + s2[i];
115	      }
116	
117	      if (variant == variant_e::EdDSA) {
118	        sigs[i] = R[i].to_compressed_bin() + s.to_bin(crypto::ed25519::prv_bin_size()).rev();
119	        crypto::ecc_pub_key_t pub_key(key.Q);
120	        if (rv = pub_key.verify(msgs[i], sigs[i])) return coinbase::error(rv, "schnorr_2p: eddsa verify failed");
121	      } else if (variant == variant_e::BIP340) {
122	        bn_t rx, ry;
123	        R[i].get_coordinates(rx, ry);
124	        sigs[i] = rx.to_bin(32) + s.to_bin(32);
125	        crypto::ecc_pub_key_t pub_key(key.Q);
126	        if (rv = crypto::bip340::verify(pub_key, msgs[i], sigs[i]))
127	          return coinbase::error(rv, "schnorr_2p: secp256k1 verify failed");
128	      } else {
129	        cb_assert(false && "schnorr_2p: non-existing variant");
130	      }
131	    }
132	  }
133	  return SUCCESS;
134	}
