52	error_t sign_batch(job_mp_t& job, key_t& key, const std::vector<mem_t>& msgs, party_idx_t sig_receiver,
53	                   std::vector<buf_t>& sigs, variant_e variant) {
54	  error_t rv = UNINITIALIZED_ERROR;
55	
56	  int n = job.get_n_parties();
57	  int i = job.get_party_idx();
58	  crypto::pname_t pname = job.get_name();
59	  sigs.resize(msgs.size());
60	
61	  ecurve_t curve = key.curve;
62	  const mod_t& q = curve.order();
63	  const auto& G = curve.generator();
64	
65	  if (key.party_name != pname) return coinbase::error(E_BADARG, "Wrong role");
66	  if (key.Qis.size() != n) return coinbase::error(E_BADARG, "Wrong number of peers");
67	  if (key.x_share * G != key.Qis.at(pname)) return coinbase::error(E_BADARG, "x_share does not match Qi");
68	  if (SUM(key.Qis) != key.Q) return coinbase::error(E_BADARG, "Q does not match the sum of Qis");
69	  auto h_consistency = job.uniform_msg<buf256_t>();
70	  h_consistency._i = crypto::sha256_t::hash(msgs, key.Q, key.Qis);
71	
72	  auto sid_i = job.uniform_msg<buf_t>(crypto::gen_random_bitlen(SEC_P_COM));
73	  auto ki = job.uniform_msg<std::vector<bn_t>>(std::vector<bn_t>(msgs.size()));
74	  auto Ri = job.uniform_msg<std::vector<ecc_point_t>>(std::vector<ecc_point_t>(msgs.size()));
75	  for (size_t l = 0; l < msgs.size(); l++) {
76	    ki[l] = bn_t::rand(q);
77	    Ri[l] = ki[l] * G;
78	  }
79	
80	  coinbase::crypto::commitment_t com(sid_i, job.get_pid(i));
81	  com.gen(Ri._i);
82	  auto c = job.uniform_msg<buf_t>(com.msg);
83	  auto rho = job.uniform_msg<buf256_t>(com.rand);
84	
85	  if (rv = job.plain_broadcast(c, sid_i, h_consistency)) return rv;
86	
87	  for (int j = 0; j < n; j++) {
88	    if (j == i) continue;
89	    if (h_consistency._j != h_consistency) return coinbase::error(E_CRYPTO);
90	  }
91	  auto sid = job.uniform_msg<buf_t>();
92	  sid._i = crypto::sha256_t::hash(sid_i._js);
93	
94	  auto h = job.uniform_msg<buf256_t>();
95	  h._i = crypto::sha256_t::hash(c._js);
96	  auto pi = job.uniform_msg<zk::uc_batch_dl_t>();
97	  pi.prove(Ri, ki, sid, i);
98	  if (rv = job.plain_broadcast(sid, h, Ri, rho, pi)) return rv;
99	
100	  for (int j = 0; j < n; j++) {
101	    if (job.is_party_idx(j)) continue;
102	
103	    if (sid._j != sid._i) return coinbase::error(E_CRYPTO);
104	    if (h._j != h._i) return coinbase::error(E_CRYPTO);
105	    if (Ri._j.size() != msgs.size())
106	      return coinbase::error(E_CRYPTO, "schnorrmp::sign_batch: inconsistent batch size (Ri)");
107	    // Verification of Ri._j is done in the zk verify function
108	    if (rv = pi._j.verify(Ri._j, sid._i, j)) return coinbase::error(rv, "schnorr_mp_t::sign_batch: verify pi failed");
109	
110	    if (rv = coinbase::crypto::commitment_t(sid_i._j, job.get_pid(j)).set(rho._j, c._j).open(Ri._j)) return rv;
111	  }
112	
113	  std::vector<ecc_point_t> R(msgs.size());
114	  for (size_t l = 0; l < msgs.size(); l++) {
115	    R[l] = Ri._i[l];
116	    for (int j = 0; j < n; j++) {
117	      if (j == i) continue;
118	      R[l] += Ri._j[l];
119	    }
120	  }
121	
122	  std::vector<bn_t> e(msgs.size());
123	
124	  if (variant == variant_e::EdDSA) {
125	    if (key.curve != crypto::curve_ed25519) return coinbase::error(E_BADARG, "EdDSA variant requires EdDSA curve");
126	    for (size_t l = 0; l < msgs.size(); l++) {
127	      e[l] = calc_eddsa_HRAM(R[l], key.Q, msgs[l]);
128	    }
129	  } else if (variant == variant_e::BIP340) {
130	    if (key.curve != crypto::curve_secp256k1)
131	      return coinbase::error(E_BADARG, "BIP340 variant requires secp256k1 curve");
132	    bn_t rx, ry;
133	    for (size_t l = 0; l < msgs.size(); l++) {
134	      if (msgs[l].size != 32) return coinbase::error(E_BADARG, "schnorr_mp: BIP340 msg size != 32");
135	      if (!msgs[l].data) return coinbase::error(E_BADARG, "schnorr_mp: BIP340 msg is null");
136	      R[l].get_coordinates(rx, ry);
137	      if (ry.is_odd()) ki[l] = q - ki[l];
138	      e[l] = crypto::bip340::hash_message(rx, key.Q, msgs[l]);
139	      if (key.Q.get_y().is_odd()) e[l] = q - e[l];
140	    }
141	  } else {
142	    cb_assert(false && "schnorr_mp: non-existing variant");
143	  }
144	
145	  auto ssi = job.uniform_msg<std::vector<bn_t>>();
146	  ssi.msg.resize(msgs.size());
147	  for (size_t l = 0; l < msgs.size(); l++) {
148	    ssi.msg[l] = (e[l] * key.x_share + ki[l]) % q;
149	  }
150	
151	  if (rv = job.send_message_all_to_one(sig_receiver, ssi)) return rv;
152	
153	  if (job.is_party_idx(sig_receiver)) {
154	    std::vector<bn_t> ss(msgs.size(), 0);
155	    for (int j = 0; j < n; j++) {
156	      if (ssi._j.size() != msgs.size())
157	        return coinbase::error(E_CRYPTO, "schnorrmp::sign_batch: inconsistent batch size (ssi)");
158	      for (size_t l = 0; l < msgs.size(); l++) MODULO(q) ss[l] += ssi._j[l];
159	    }
160	
161	    crypto::ecc_pub_key_t verify_key(key.Q);
162	    if (key.curve == crypto::curve_ed25519) {
163	      for (size_t l = 0; l < msgs.size(); l++) {
164	        sigs[l] = R[l].to_compressed_bin() + ss[l].to_bin(crypto::ed25519::prv_bin_size()).rev();
165	        if (rv = verify_key.verify(msgs[l], sigs[l])) return coinbase::error(rv, "ed25519 verify failed");
166	      }
167	    } else if (key.curve == crypto::curve_secp256k1) {
168	      bn_t rx, ry;
169	      for (size_t l = 0; l < msgs.size(); l++) {
170	        R[l].get_coordinates(rx, ry);
171	        sigs[l] = rx.to_bin(32) + ss[l].to_bin(32);
172	        if (rv = crypto::bip340::verify(verify_key, msgs[l], sigs[l])) {
173	          return coinbase::error(rv, "bip340 verify failed");
174	        }
175	      }
176	    } else {
177	      cb_assert(false && "schnorr_mp: non-existing variant");
178	    }
179	  }
180	  return SUCCESS;
181	}
